mapper.select:
SELECT s.id, s.university_id, u.name AS university_name, u.code AS university_code, u.level AS university_level, u.type AS university_type, u.province AS university_province, u.city AS university_city, s.major_id, NULL AS major_name, s.province, s.year, s.batch, s.subject_type, s.min_score, s.avg_score, s.max_score, s.min_rank, s.max_rank, s.enrollment, s.admitted FROM admission_score s LEFT JOIN university u ON s.university_id = u.id
AND s.university_id = #{universityId}
AND s.province = #{province}
AND s.subject_type = #{subjectType}
AND s.year = #{year}
AND s.min_score >= #{minScoreFrom}
AND s.min_score <= #{minScoreTo}
ORDER BY s.year DESC, s.min_score DESC

SELECT s.id, s.university_id, u.name AS university_name, u.code AS university_code, u.level AS university_level, u.type AS university_type, u.province AS university_province, u.city AS university_city, s.major_id, NULL AS major_name, s.province, s.year, s.batch, s.subject_type, s.min_score, s.avg_score, s.max_score, s.min_rank, s.max_rank, s.enrollment, s.admitted FROM admission_score s LEFT JOIN university u ON s.university_id = u.id
AND s.province = #{province}
AND s.subject_type = #{subjectType}
AND s.year = #{year}
AND s.min_score >= #{minScore}
AND s.min_score <= #{maxScore}
ORDER BY s.min_score DESC
LIMIT #{limit}

SELECT s.id, s.university_id, u.name AS university_name, u.code AS university_code, u.level AS university_level, u.type AS university_type, u.province AS university_province, u.city AS university_city, s.major_id, NULL AS major_name, s.province, s.year, s.batch, s.subject_type, s.min_score, s.avg_score, s.max_score, s.min_rank, s.max_rank, s.enrollment, s.admitted FROM admission_score s LEFT JOIN university u ON s.university_id = u.id
AND s.university_id = #{universityId}
AND s.province = #{province}
AND s.subject_type = #{subjectType}
AND s.year IN
#{year}
ORDER BY s.year DESC

SELECT COUNT(*) AS total_count, MIN(min_score) AS min_score_min, MAX(min_score) AS min_score_max, AVG(min_score) AS min_score_avg, MIN(min_rank) AS min_rank_min, MAX(min_rank) AS min_rank_max, AVG(min_rank) AS min_rank_avg, SUM(enrollment) AS total_enrollment FROM admission_score
AND university_id = #{universityId}
AND province = #{province}
AND subject_type = #{subjectType}

SELECT s.id, s.university_id, u.name AS university_name, u.code AS university_code, u.level AS university_level, u.type AS university_type, u.province AS university_province, u.city AS university_city, s.major_id, NULL AS major_name, s.province, s.year, s.batch, s.subject_type, s.min_score, s.avg_score, s.max_score, s.min_rank, s.max_rank, s.enrollment, s.admitted FROM admission_score s LEFT JOIN university u ON s.university_id = u.id
AND s.province = #{province}
AND s.subject_type = #{subjectType}
AND s.year = #{year}
AND s.min_score BETWEEN #{score} - #{range} AND #{score} + #{range}
AND u.level = #{level}
ORDER BY ABS(s.min_score - #{score}) ASC, u.ranking ASC
LIMIT #{limit}

SELECT u.level, COUNT(*) AS university_count, MIN(s.min_score) AS min_score_min, MAX(s.min_score) AS min_score_max, AVG(s.min_score) AS min_score_avg, SUM(s.enrollment) AS total_enrollment FROM admission_score s LEFT JOIN university u ON s.university_id = u.id
AND s.province = #{province}
AND s.year = #{year}
GROUP BY u.level ORDER BY min_score_avg DESC
